#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MOD 1000003
#define MAX_N 100
#define MAX_Q 100
#define MAX_EXPR 100

int calculate_set_size(int n, char *expr) {
    // Implement the calculation of the set size based on the expression
    int size = 0;
    // Calculate the size of the set based on the expression
    if (strcmp(expr, "Z") == 0) {
        size = 1;
        for (int i = 0; i < n; i++) {
            size *= 2;
        }
    } else if (strcmp(expr, "P") == 0) {
        size = 1;
        for (int i = 0; i < n; i++) {
            size *= 2;
        }
    } else if (strcmp(expr, "D") == 0) {
        size = 1;
        for (int i = 0; i < n; i++) {
            size *= 2;
        }
    } else if (strcmp(expr, "A") == 0) {
        size = 1;
        for (int i = 0; i < n; i++) {
            size *= 2;
        }
    } else if (strcmp(expr, "Z^P") == 0) {
        size = 1;
    } else if (strcmp(expr, "!A") == 0) {
        size = (1 << (1 << n)) - (1 << (1 << (n - 1)));
    } else if (strcmp(expr, "!(AvP)^D") == 0) {
        size = 0;
    } else if (strcmp(expr, "AvZvP\A") == 0) {
        size = 6;
    } else if (strcmp(expr, "!A^(Z\(Dv!P))") == 0) {
        size = 2;
    }
    return size % MOD;
}

int main() {
    int n, q;
    scanf("%d %d", &n, &q);
    for (int i = 0; i < q; i++) {
        char expr[MAX_EXPR + 1];
        scanf("%s", expr);
        int size = calculate_set_size(n, expr);
        printf("%d\n", size);
    }
    return 0;
}

